    positions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    positions[i * 3 + 2] = r * Math.cos(phi);

    // 쿼크와 글루온 색상 랜덤
    const type = Math.random();
    if (type < 0.3) {
      // 업 쿼크: 빨강
      colors[i * 3] = 1.0;
      colors[i * 3 + 1] = 0.2;
      colors[i * 3 + 2] = 0.2;
